def merge_ranges(pairs):
    if not pairs:
        return []

    pairs.sort()
    merged = [pairs[0]]

    for start, end in pairs[1:]:
        last_end = merged[-1][1]

        if start <= last_end + 1:
            merged[-1] = [merged[-1][0], max(end, last_end)]
        else:
            merged.append([start, end])

    return merged
